(function(){"use strict";const r="http://localhost:3000";chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.removeAll(()=>{chrome.contextMenus.create({id:"inline-analyze-risk",title:"Analyze page risk (Inline)",contexts:["page"]}),chrome.contextMenus.create({id:"inline-root",title:"Inline",contexts:["selection"]}),chrome.contextMenus.create({id:"notes",parentId:"inline-root",title:"📝 Add Note",contexts:["selection"]}),chrome.contextMenus.create({id:"highlight",parentId:"inline-root",title:"🖊️ Highlight",contexts:["selection"]}),chrome.contextMenus.create({id:"rewrite",parentId:"inline-root",title:"✏️ Rewrite",contexts:["selection"]}),chrome.contextMenus.create({id:"ai",parentId:"inline-root",title:"✨ Ask AI",contexts:["selection"]}),chrome.contextMenus.create({id:"draw",parentId:"inline-root",title:"🎨 Draw",contexts:["selection"]}),chrome.contextMenus.create({id:"inline-draw",title:"Draw on page (Inline)",contexts:["page"]})})}),chrome.contextMenus.onClicked.addListener((e,t)=>{if(e.menuItemId==="inline-analyze-risk"&&t?.id!=null){chrome.tabs.sendMessage(t.id,{type:"INLINE_PAGE_RISK"}).catch(()=>{});return}if(e.menuItemId==="inline-draw"&&t?.id!=null){chrome.tabs.sendMessage(t.id,{type:"INLINE_FEATURE",featureId:"draw",selectedText:""}).catch(()=>{});return}!t?.id||e.menuItemId==="inline-root"||chrome.tabs.sendMessage(t.id,{type:"INLINE_FEATURE",featureId:e.menuItemId,selectedText:e.selectionText??""})}),chrome.runtime.onMessage.addListener((e,t,i)=>{if(e.type==="SAVE_ANNOTATIONS"){const{pageUrl:o,featureKey:c,data:s}=e.payload;return fetch(`${r}/api/annotations`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({pageUrl:o,featureKey:c,data:s})}).then(n=>n.json()).then(n=>i({ok:!0,data:n})).catch(n=>i({ok:!1,error:n.message})),!0}})})();
